import{_ as e,o as a,c as p,ag as r}from"./chunks/framework.BuUvxvtQ.js";const o="/assets/%E8%8A%AF%E7%89%87%E7%A7%8D%E7%B1%BB.hGvAwQzU.png",s="/assets/%E8%8A%AF%E7%89%87%E5%91%BD%E5%90%8D%E8%A7%84%E5%88%99.ZHIB-OWY.png",i="/assets/MPU%E5%91%BD%E5%90%8D%E8%A7%84%E5%88%99.CEthzAfl.png",h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"ES/Stm32/Stm32开发/Stm32简介.md","filePath":"ES/Stm32/Stm32开发/Stm32简介.md","lastUpdated":1775898880000}'),l={name:"ES/Stm32/Stm32开发/Stm32简介.md"};function n(c,t,_,m,d,S){return a(),p("div",null,[...t[0]||(t[0]=[r('<p>STM32 是意法半导体 (STMicroelectronics) 推出的基于 ARM Cortex-M 内核的微控制器系列，有着丰富的外设资源和良好的实时性以及社区开发环境。</p><p>ARM Cortex系列：</p><ul><li><p>Cortex-A—面向性能密集型系统的应用处理器内核。</p></li><li><p>Cortex-R—面向实时应用的高性能内核。</p></li><li><p>Cortex-M—面向各类嵌入式应用的微控制器内核。</p></li></ul><h3 id="系列型号" tabindex="-1">系列型号 <a class="header-anchor" href="#系列型号" aria-label="Permalink to &quot;系列型号&quot;">​</a></h3><p>意法半导体芯片的种类繁多，主要系列如下：</p><p><img src="'+o+'" alt="芯片种类"></p><h3 id="命名规则" tabindex="-1">命名规则 <a class="header-anchor" href="#命名规则" aria-label="Permalink to &quot;命名规则&quot;">​</a></h3><p>芯片的命名包含了芯片的基本信息，具体命名规则如下：</p><p>MCU</p><p><img src="'+s+'" alt="芯片命名规则"></p><p>MPU</p><p><img src="'+i+'" alt="MPU命名规则"></p><p>选型手册：<a href="https://static.stmcu.com.cn/upload/Selection_Guide.pdf" target="_blank" rel="noreferrer">Selection_Guide.pdf</a></p><p>PS. MPU 和 MCU的最主要的区别就是 MPU 的性能更强具有 MMU（内存管理单元）能够运行 Linux 操作系统，而 MCU 则只能运行 FreeRTOS 这类实时操作系统。</p>',14)])])}const u=e(l,[["render",n]]);export{h as __pageData,u as default};
